mapper.select:
SELECT r.*, s.name AS student_name, t.name AS teacher_name, c.name AS course_name, cr.name AS classroom_name FROM class_record r LEFT JOIN sys_user s ON r.student_id = s.id LEFT JOIN sys_user t ON r.teacher_id = t.id LEFT JOIN course c ON r.course_id = c.id LEFT JOIN classroom cr ON r.classroom_id = cr.id
AND r.student_id = #{param.studentId} AND r.teacher_id = #{param.teacherId}
ORDER BY r.class_time DESC
